void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("sailor2_1");			link.l1 = StringFromKey("sailor2_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("sailor2_3");			link.l1 = StringFromKey("sailor2_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("sailor2_5");			link.l1 = StringFromKey("sailor2_6");			link.l1.go = "exit";			pchar.MainQuest = "FL3_s37";			NextDiag.TempNode = "3";		break;		case "3":			if (CheckAttribute(pchar, "MainQuest") && pchar.MainQuest == "FL3_s42")			{				dialog.text = StringFromKey("sailor2_7");				link.l1 = StringFromKey("sailor2_8");				link.l1.go = "4";				break;			}			dialog.text = StringFromKey("sailor2_9");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "3";		break;		case "4":			dialog.text = StringFromKey("sailor2_10");			link.l1 = "...";			link.l1.go = "exit";			AddDialogExitQuest("FL3_s43");			NextDiag.TempNode = "5";		break;		case "5":			dialog.text = "...";			link.l1 = StringFromKey("sailor2_11");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("sailor2_12");			link.l1 = StringFromKey("sailor2_13");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("sailor2_14");			link.l1 = StringFromKey("sailor2_15");			link.l1.go = "8";		break;		case "8":			dialog.text = StringFromKey("sailor2_16");			link.l1 = StringFromKey("sailor2_17");			link.l1.go = "9";		break;		case "9":			dialog.text = StringFromKey("sailor2_18");			link.l1 = StringFromKey("sailor2_19");			link.l1.go = "10";		break;		case "10":			dialog.text = StringFromKey("sailor2_20");			link.l1 = StringFromKey("sailor2_21");			link.l1.go = "11";		break;		case "11":			dialog.text = StringFromKey("sailor2_22");			link.l1 = StringFromKey("sailor2_23");			link.l1.go = "12";		break;		case "12":			dialog.text = StringFromKey("sailor2_24");			link.l1 = StringFromKey("sailor2_25");			link.l1.go = "13";		break;		case "13":			dialog.text = StringFromKey("sailor2_26");			link.l1 = StringFromKey("sailor2_27");			link.l1.go = "14";		break;		case "14":			dialog.text = StringFromKey("sailor2_28");			link.l1 = StringFromKey("sailor2_29");			link.l1.go = "15";		break;		case "15":			dialog.text = StringFromKey("sailor2_30");			link.l1 = StringFromKey("sailor2_31");			link.l1.go = "16";		break;		case "16":			dialog.text = StringFromKey("sailor2_32");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "17";		break;		case "17":			dialog.text = StringFromKey("sailor2_33");			link.l1 = StringFromKey("sailor2_34");			link.l1.go = "18";		break;		case "18":			dialog.text = StringFromKey("sailor2_35");			link.l1 = StringFromKey("sailor2_36");			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}